class Solution:
    def findPrefixScore(self, nums):
        n = len(nums)
        conver = []
        for i in range(n):
            m = nums[0]
            for j in range(1, i + 1):
                if nums[j] > m:
                    m = nums[j]
            conver.append(nums[i] + m)
        res = []
        total = 0
        for c in conver:
            total += c
            res.append(total)
        return res

