var findPrefixScore = function(nums) {
    const res = [];
    let runningMax = nums[0];
    let total = 0;
    for (const x of nums) {
        if (x > runningMax) runningMax = x;
        total += x + runningMax;
        res.push(total);
    }
    return res;
